[CmdletBinding()]
param([string]$Root=(Get-Location).Path,[ValidateSet('solo','startup','enterprise','regulated')][string]$TeamProfile='solo',[switch]$Json)
$ErrorActionPreference='Stop';$signals=@();if(Test-Path (Join-Path $Root 'package.json')){$signals+='node'};if(Test-Path (Join-Path $Root '*.sln')){$signals+='dotnet'};if(Test-Path (Join-Path $Root '.git')){$signals+='git'};$result=[ordered]@{schemaVersion=1;root=$Root;detectedSignals=$signals;teamProfile=$TeamProfile;firstRules=@('Run environment bootstrap before inspection.','Use task preflight for non-trivial work.','Keep capabilities proportional to task risk.','Record explicit project decisions only in local memory.','Require evidence before completion.');dryRun=$true;mutation=$false;nextAction='Review this preview, then choose an explicit installation or project configuration action.'};if($Json){$result|ConvertTo-Json}else{$result|Format-List}
